/**
 * Hotspot
 *
 * Clickable (desktop) and raycast-selectable (VR) marker positioned by lat/lon.
 */

import * as THREE from 'three';
import { latLonToVector3 } from './Utils.js';

export class Hotspot {
  /**
   * @param {object} data row from `hotspots`
   * @param {object} opts
   * @param {number} [opts.radius]
   */
  constructor(data, { radius = 495 } = {}) {
    this.data = data;
    this.radius = radius;
    this._theme = {
      accent: 0x4f8cff,
      outline: 0x4f8cff,
      glyph: 0x0b0f19
    };
    this.object3d = this._createMesh();
    this.object3d.userData.hotspot = this;
    this.setSelected(false);
  }

  _createMesh() {
    const type = String(this.data?.type || 'pov').toLowerCase();
    if (type === 'door') return this._createIconMarker('door');
    if (type === 'stairs') return this._createIconMarker('stairs');
    // default: point-of-view / navigate
    return this._createIconMarker('pov');
  }

  _createIconMarker(iconType) {
    // Icon marker: SVG glyph only (no badge/background), per user request.
    const group = new THREE.Group();
    group.name = `Hotspot:${iconType}:${this.data?.id || ''}`;

    const tex = this._createIconTexture(iconType);
    tex.colorSpace = THREE.SRGBColorSpace;
    tex.needsUpdate = true;

    const iconMat = new THREE.MeshBasicMaterial({
      map: tex,
      transparent: true,
      opacity: 1,
      depthTest: true,
      depthWrite: false
    });
    const iconGeo = new THREE.PlaneGeometry(64, 64);
    const icon = new THREE.Mesh(iconGeo, iconMat);
    group.add(icon);

    group.position.copy(latLonToVector3(this.data.lat, this.data.lon, this.radius));
    group.lookAt(0, 0, 0);

    group.userData._hotspotMats = [iconMat];
    group.userData._hotspotTex = tex;
    group.userData._hotspotIconType = iconType;
    return group;
  }

  _createIconTexture(iconType) {
    // Canvas-drawn icon so it stays crisp and contrasted against varied pano backgrounds.
    const size = 256;
    const canvas = document.createElement('canvas');
    canvas.width = size;
    canvas.height = size;
    const ctx = canvas.getContext('2d');

    // Keep canvas reference to allow recoloring later (theme updates).
    const meta = { canvas, ctx, size, iconType };
    const texture = new THREE.CanvasTexture(canvas);
    texture.anisotropy = 8;
    texture.minFilter = THREE.LinearMipmapLinearFilter;
    texture.magFilter = THREE.LinearFilter;
    texture.userData = meta;

    this._drawIconToCanvas(meta, this._theme);

    return texture;
  }

  _drawIconToCanvas(meta, theme) {
    const { ctx, size, iconType } = meta;
    const cx = size / 2;
    const cy = size / 2;

    // Glyph only (no background).
    ctx.clearRect(0, 0, size, size);

    // SVG glyph (provided by user), drawn via Path2D so it stays sharp.
    ctx.save();
    // Tiny shadow for legibility; still "SVG only" (no badge/background).
    ctx.shadowColor = 'rgba(0,0,0,0.45)';
    ctx.shadowBlur = 10;
    ctx.shadowOffsetY = 2;
    ctx.fillStyle = 'rgba(255,255,255,0.98)';
    this._drawSvgGlyph(ctx, iconType, { cx, cy, size });
    ctx.restore();
  }

  _getSvgSpec(iconType) {
    // User-provided SVG paths (white glyph). We draw via Path2D(d).
    // Note: We only need the `d` values; clipPaths are ignored.
    const DOOR = {
      viewBox: [0, 0, 120, 120],
      d: [
        'M75.0089 0V5.29218H95.7031V110.882H88.0525V12.9437H75.0089V120L24.2978 110.882V95.9617V9.13706L75.0089 0ZM65.6799 64.1127C67.3846 64.1127 68.7667 62.3142 68.7667 60.0958C68.7667 57.8775 67.3846 56.0791 65.6799 56.0791C63.9752 56.0791 62.5931 57.8775 62.5931 60.0958C62.5931 62.3142 63.9752 64.1127 65.6799 64.1127Z'
      ]
    };

    const POV = {
      viewBox: [0, 0, 120, 120],
      d: [
        'M75 60C75 68.27 68.27 75 60 75C51.73 75 45 68.27 45 60C45 51.73 51.73 45 60 45C68.27 45 75 51.73 75 60ZM120 57.755C120 57.755 98.74 100 60.075 100C24.175 100 0 57.755 0 57.755C0 57.755 22.23 20 60.075 20C98.545 20 120 57.755 120 57.755ZM85 60C85 46.215 73.785 35 60 35C46.215 35 35 46.215 35 60C35 73.785 46.215 85 60 85C73.785 85 85 73.785 85 60Z'
      ]
    };

    const STAIRS = {
      viewBox: [0, 0, 120, 100],
      d: [
        'M114.783 8.33337H88.6957C85.8156 8.33337 83.4782 10.196 83.4782 12.5001V29.1668H78.2608V8.33337H83.4782C86.3582 8.33337 88.6957 6.47077 88.6957 4.16668C88.6957 1.8626 86.3582 0 83.4782 0H73.0433C73.012 0 72.9807 0.0124105 72.9493 0.0124105C72.5267 0.020752 72.1249 0.124919 71.7181 0.212403C71.4677 0.266521 71.1964 0.270794 70.9615 0.354005C70.7266 0.433148 70.5337 0.591433 70.3144 0.703942C69.9595 0.883182 69.5891 1.04147 69.2969 1.28317C69.276 1.30392 69.2447 1.30819 69.2187 1.32894L1.39202 59.6625C-0.564515 61.3499 -0.444524 63.9875 1.66334 65.55C2.6704 66.2958 3.94342 66.6667 5.21644 66.6667C6.61481 66.6667 8.01292 66.2167 9.04086 65.3333L10.4339 64.1374V70.8332C7.55384 70.8332 5.21644 72.6958 5.21644 74.9999V95.8333C5.21644 98.1374 7.55384 100 10.4339 100H114.783C117.663 100 120 98.1374 120 95.8333V12.5001C120 10.196 117.663 8.33337 114.783 8.33337ZM36.5213 50.0002C33.6413 50.0002 31.3039 51.8628 31.3039 54.1669V70.8336H20.869V55.1628L36.5213 41.7002V50.0002ZM67.8259 29.1668H62.6085C59.7284 29.1668 57.391 31.0294 57.391 33.3335V50.0002H46.9562V33.3335C46.9562 33.1542 46.8571 33.0043 46.8308 32.8334L67.8259 14.7791V29.1668Z'
      ]
    };

    if (iconType === 'door') return DOOR;
    if (iconType === 'stairs') return STAIRS;
    return POV;
  }

  _drawSvgGlyph(ctx, iconType, { cx, cy, size }) {
    const spec = this._getSvgSpec(iconType);
    const [, , vbW, vbH] = spec.viewBox;

    // Target size inside the badge with some padding.
    const target = 170; // pixels in the 256x256 texture
    const scale = Math.min(target / vbW, target / vbH);
    const drawW = vbW * scale;
    const drawH = vbH * scale;
    const ox = cx - drawW / 2;
    const oy = cy - drawH / 2;

    ctx.save();
    ctx.translate(ox, oy);
    ctx.scale(scale, scale);
    for (const d of spec.d) {
      try {
        const p = new Path2D(d);
        ctx.fill(p);
      } catch {
        // If Path2D fails (older browsers), fall back to a simple circle.
        // (Still keeps hotspots usable.)
        ctx.restore();
        ctx.beginPath();
        ctx.arc(cx, cy, 10, 0, Math.PI * 2);
        ctx.fill();
        return;
      }
    }
    ctx.restore();

    void size;
  }

  /**
   * Apply a theme (per-panorama) so icons can be outlined with the pano's dominant/average color.
   * @param {{accent?:number, outline?:number, glyph?:number}} theme
   */
  setTheme(theme = {}) {
    this._theme = { ...this._theme, ...(theme || {}) };
    const obj = this.object3d;
    const tex = obj?.userData?._hotspotTex;
    const glowMat = obj?.userData?._hotspotMats?.[1] || null;
    if (glowMat?.color) glowMat.color.setHex(this._theme.accent);

    const meta = tex?.userData;
    if (meta?.ctx && meta?.canvas) {
      this._drawIconToCanvas(meta, this._theme);
      tex.needsUpdate = true;
    }
  }

  _roundRect(ctx, x, y, w, h, r) {
    ctx.beginPath();
    ctx.moveTo(x + r, y);
    ctx.arcTo(x + w, y, x + w, y + h, r);
    ctx.arcTo(x + w, y + h, x, y + h, r);
    ctx.arcTo(x, y + h, x, y, r);
    ctx.arcTo(x, y, x + w, y, r);
    ctx.closePath();
  }

  setSelected(isSelected) {
    // Selection styling:
    // - don't tint the icon texture (keeps icons crisp)
    // - boost glow + slightly scale up
    const mats = this.object3d.userData._hotspotMats || [];
    const iconMat = mats[0] || null;
    const glowMat = mats[1] || null;
    const haloMat = mats[2] || null;

    if (iconMat) {
      iconMat.opacity = isSelected ? 1.0 : 0.92;
      // Keep texture un-tinted
      if (iconMat.color) iconMat.color.setHex(0xffffff);
    }
    if (glowMat) {
      glowMat.opacity = isSelected ? 0.35 : 0.22;
      if (glowMat.color) glowMat.color.setHex(this._theme.accent);
    }
    if (haloMat) {
      haloMat.opacity = isSelected ? 0.28 : 0.18;
      if (haloMat.color) haloMat.color.setHex(0xffffff);
    }
    this.object3d.scale.setScalar(isSelected ? 1.18 : 1.0);
  }

  dispose() {
    const obj = this.object3d;
    if (!obj) return;
    const tex = obj.userData?._hotspotTex;
    if (tex?.dispose) tex.dispose();
    obj.traverse((child) => {
      if (!child.isMesh) return;
      if (child.geometry) child.geometry.dispose();
      if (child.material) child.material.dispose();
    });
  }
}


