/**
 * Script embed entry.
 *
 * Builds to dist/panorama360.min.js and exposes:
 *   window.Panorama360.init({ container, projectId, supabaseUrl?, supabaseAnonKey? })
 *   window.Panorama360.loadPanorama(id)
 *   window.Panorama360.enterVR()
 *   window.Panorama360.exitVR()
 *   window.Panorama360.toggleFloorplan()
 *   window.Panorama360.destroy()
 */

import './styles/viewer.css';
import { Viewer } from './core/Viewer.js';
import { ensureViewerStyles } from './core/ensureViewerStyles.js';

let _active = null;

export async function init(options) {
  ensureViewerStyles();
  if (_active) await _active.destroy();
  const supabaseUrl = options?.supabaseUrl || import.meta.env.VITE_SUPABASE_URL;
  const supabaseAnonKey = options?.supabaseAnonKey || import.meta.env.VITE_SUPABASE_ANON_KEY;
  if (!supabaseUrl || /YOUR-PROJECT\.supabase\.co/i.test(supabaseUrl)) {
    throw new Error('Panorama360: missing VITE_SUPABASE_URL (replace template YOUR-PROJECT and restart Vite)');
  }
  if (!supabaseAnonKey || /^YOUR_/i.test(supabaseAnonKey)) {
    throw new Error('Panorama360: missing VITE_SUPABASE_ANON_KEY (replace template value and restart Vite)');
  }
  _active = new Viewer({ ...options, supabaseUrl, supabaseAnonKey });
  await _active.init();
  return _active;
}

export async function loadPanorama(id) {
  if (!_active) throw new Error('Panorama360: call init() first');
  return await _active.loadPanorama(id, { reason: 'api' });
}

export function getViewYawPitch() {
  if (!_active) throw new Error('Panorama360: call init() first');
  return _active.getViewYawPitch();
}

export function toggleFloorplan() {
  if (!_active) throw new Error('Panorama360: call init() first');
  return _active.toggleFloorplan();
}

export async function enterVR() {
  if (!_active) throw new Error('Panorama360: call init() first');
  return await _active.enterVR();
}

export async function exitVR() {
  if (!_active) throw new Error('Panorama360: call init() first');
  return await _active.exitVR();
}

export async function destroy() {
  if (!_active) return;
  const v = _active;
  _active = null;
  await v.destroy();
}

export const Panorama360 = {
  init,
  loadPanorama,
  getViewYawPitch,
  enterVR,
  exitVR,
  toggleFloorplan,
  destroy
};

// Ensure a stable global in both IIFE and ESM contexts.
if (typeof window !== 'undefined') window.Panorama360 = Panorama360;


