/**
 * SupabaseService
 *
 * Single responsibility: read tour configuration/data and write analytics.
 * This is the only module that touches Supabase directly.
 */

import { createClient } from '@supabase/supabase-js';
import { safeJsonParse } from './Utils.js';

export class SupabaseService {
  /**
   * @param {object} opts
   * @param {string} opts.supabaseUrl
   * @param {string} opts.supabaseAnonKey
   */
  constructor({ supabaseUrl, supabaseAnonKey } = {}) {
    if (!supabaseUrl) throw new Error('Panorama360: supabaseUrl is required');
    if (!supabaseAnonKey) throw new Error('Panorama360: supabaseAnonKey is required');
    const key = String(supabaseAnonKey).trim();
    if (!key.startsWith('eyJ')) {
      throw new Error(
        'Panorama360: supabaseAnonKey looks invalid. Use the "anon public" API key from Supabase Dashboard → Project Settings → API.'
      );
    }
    this.client = createClient(supabaseUrl, supabaseAnonKey, {
      auth: { persistSession: false, autoRefreshToken: false },
      global: undefined
    });

    // Cache normalized project tour data so we can support:
    // - normalized schema (panoramas/hotspots/floorplans tables)
    // - compact schema (projects.tour_data JSON)
    this._projectCache = new Map();

    // If PostgREST returns 404 for a table, remember and stop hitting it.
    // This avoids noisy 404s when your schema only uses `projects.tour_data`.
    this._missingTables = new Set();
  }

  _markTableMissingIf404(tableName, res) {
    const status = res?.status;
    const statusText = res?.statusText || '';
    const msg = res?.error?.message || '';
    const looksMissing =
      status === 404 ||
      /not found/i.test(statusText) ||
      /could not find/i.test(msg) ||
      /relation .* does not exist/i.test(msg) ||
      /schema cache/i.test(msg);
    if (looksMissing) this._missingTables.add(tableName);
    return looksMissing;
  }

  async getProject(projectId) {
    const { data, error } = await this.client.from('projects').select('*').eq('id', projectId).single();
    if (error) throw new Error(`Panorama360: failed to load project: ${error.message}`);
    const { project, tour } = this._normalizeProjectRow(data);
    this._projectCache.set(projectId, { project, tour });
    return project;
  }

  getCachedTourData(projectId) {
    return this._projectCache.get(projectId)?.tour || null;
  }

  _normalizeProjectRow(row) {
    const tour =
      row?.tour_data && typeof row.tour_data === 'string'
        ? safeJsonParse(row.tour_data, {})
        : (row?.tour_data || {});

    const floorplan =
      row?.floorplan_data && typeof row.floorplan_data === 'string'
        ? safeJsonParse(row.floorplan_data, null)
        : (row?.floorplan_data ?? null);

    const images =
      row?.images && typeof row.images === 'string'
        ? safeJsonParse(row.images, null)
        : (row?.images ?? null);

    const settings = {
      ...(row?.settings || {}),
      ...(tour?.settings || {})
    };

    const scenes = tour?.scenes && typeof tour.scenes === 'object' ? tour.scenes : {};
    const firstScene = Object.values(scenes)[0] || null;
    if (!settings.start_panorama_id && firstScene?.id) settings.start_panorama_id = firstScene.id;

    const project = {
      ...row,
      settings,
      tour_data: tour,
      floorplan_data: floorplan,
      images
    };

    return { project, tour };
  }

  async getPanoramas(projectId) {
    // Prefer normalized tables if present; otherwise derive from projects.tour_data.
    if (!this._missingTables.has('panoramas')) {
      const tableAttempt = await this.client
        .from('panoramas')
        .select('*')
        .eq('project_id', projectId);
      if (!tableAttempt.error) return tableAttempt.data || [];
      if (!this._markTableMissingIf404('panoramas', tableAttempt)) {
        throw new Error(`Panorama360: failed to load panoramas: ${tableAttempt.error.message}`);
      }
    }

    // Fallback: derive from tour_data
    if (!this._projectCache.has(projectId)) await this.getProject(projectId);
    const cached = this._projectCache.get(projectId) || { tour: {} };
    const scenes = cached.tour?.scenes && typeof cached.tour.scenes === 'object' ? cached.tour.scenes : {};

    return Object.values(scenes).map((scene) => ({
      id: scene.id,
      project_id: projectId,
      name: scene.name || null,
      image_url: scene.image || null,
      image3d_url: scene.image3d || null,
      // Optional: allow floorplan room mapping for SVG highlighting/navigation.
      room_id: scene.roomId || scene.room_id || scene.floorplanRoomId || scene.floorplan_room_id || null,
      floorplan_id: null,
      floorplan_x: null,
      floorplan_y: null
    }));
  }

  async getHotspotsByPanorama(panoramaId) {
    if (!this._missingTables.has('hotspots')) {
      const tableAttempt = await this.client
        .from('hotspots')
        .select('*')
        .eq('panorama_id', panoramaId);
      if (!tableAttempt.error) {
        const rows = tableAttempt.data || [];
        // Normalize hotspot coordinate fields across possible schemas:
        // - preferred: { lat, lon }
        // - legacy: { pitch, yaw }
        // - compact/other: { y, x }
        //
        // The viewer expects degrees:
        // - lat: [-90..90]
        // - lon: [-180..180]
        return rows.map((r) => {
          const lat =
            (r?.lat ?? r?.pitch ?? r?.y ?? null);
          const lon =
            (r?.lon ?? r?.yaw ?? r?.x ?? null);
          return {
            ...r,
            lat: Number(lat ?? 0),
            lon: Number(lon ?? 0)
          };
        });
      }
      if (!this._markTableMissingIf404('hotspots', tableAttempt)) {
        throw new Error(`Panorama360: failed to load hotspots: ${tableAttempt.error.message}`);
      }
    }

    // Fallback: derive from cached tour_data (scenes[*].hotspots)
    for (const { tour } of this._projectCache.values()) {
      const scenes = tour?.scenes && typeof tour.scenes === 'object' ? tour.scenes : {};
      const scene = scenes?.[panoramaId] || Object.values(scenes).find((s) => s?.id === panoramaId);
      if (!scene) continue;

      const hs = Array.isArray(scene.hotspots) ? scene.hotspots : [];
      return hs.map((h, idx) => ({
        id: `${scene.id || panoramaId}::${idx}`,
        panorama_id: scene.id || panoramaId,
        type: h.type || 'navigate',
        lon: Number(h.yaw ?? 0),
        lat: Number(h.pitch ?? 0),
        target_panorama_id: h.targetId || null,
        camera: null,
        label: h.label || null,
        preview: h.preview || null
      }));
    }

    return [];
  }

  async getFloorplans(projectId) {
    if (!this._missingTables.has('floorplans')) {
      const tableAttempt = await this.client
        .from('floorplans')
        .select('*')
        .eq('project_id', projectId);
      if (!tableAttempt.error) return tableAttempt.data || [];
      if (!this._markTableMissingIf404('floorplans', tableAttempt)) {
        throw new Error(`Panorama360: failed to load floorplans: ${tableAttempt.error.message}`);
      }
    }

    // Fallback: single floorplan stored on projects.floorplan_data (if present).
    if (!this._projectCache.has(projectId)) await this.getProject(projectId);
    const cached = this._projectCache.get(projectId) || { project: null };
    const fp = cached.project?.floorplan_data;
    if (!fp) return [];

    // Best-effort mapping; you can extend once floorplan_data shape is known.
    const imageUrl =
      fp?.image_url ||
      fp?.png_url ||
      fp?.floorplan_png ||
      fp?.imageUrl ||
      fp?.floorplanPng ||
      null;
    const svgUrl =
      fp?.svg_url ||
      fp?.svgUrl ||
      fp?.floorplan_svg ||
      fp?.floorplanSvg ||
      null;

    if (imageUrl) {
      return [{
        id: fp.id || 'floorplan:0',
        project_id: projectId,
        image_url: imageUrl,
        svg_url: svgUrl,
        width: fp.width || 1,
        height: fp.height || 1
      }];
    }

    return [];
  }

  // (analytics removed)
}


