/**
 * CameraController
 *
 * Controls panorama look-around (yaw/pitch) and zoom (FOV).
 * Uses GSAP for smooth transitions and optional idle auto-rotate.
 */

import { gsap } from 'gsap';
import { clamp, nowMs } from './Utils.js';

export class CameraController {
  /**
   * @param {object} opts
   * @param {import('three').PerspectiveCamera} opts.camera
   * @param {HTMLCanvasElement} opts.canvas
   */
  constructor({ camera, canvas }) {
    this.camera = camera;
    this.canvas = canvas;

    // Current (rendered) angles
    this.yaw = 0;
    this.pitch = 0;
    // Target angles (smoothed towards)
    this.targetYaw = 0;
    this.targetPitch = 0;
    this.minPitch = -1.35;
    this.maxPitch = 1.35;

    // Allow a bit wider FOV for "zoomed out" view.
    this.minFov = 45;
    this.maxFov = 110;

    // Default OFF (user requested). Can be toggled via HUD.
    this.autoRotateEnabled = false;

    this._dragging = false;
    this._lastX = 0;
    this._lastY = 0;
    this._lastMoveMs = null;

    this._lastInteractionMs = nowMs();
    this._lastTickMs = null;
    this.idleDelayMs = 5000;
    this.autoRotateSpeed = 0.0001; // radians per ms (more obvious)

    // Smoothness tuning
    this.damping = 0.001; // higher = snappier, lower = smoother (tuned to avoid "laggy" feel)
    this.inertiaFriction = 0.92; // closer to 1 = longer glide
    this._yawVel = 0; // rad/ms
    this._pitchVel = 0; // rad/ms

    // Drag sensitivity (radians per pixel). Lower = slower camera when dragging.
    // User request: slow down camera movement a bit.
    this.dragSensitivity = 0.0009; // was 0.003

    // User-requested interaction: invert horizontal drag direction
    // (mouse right -> camera left, mouse left -> camera right)
    this.invertDragX = true;
    this.invertDragY = false;

    this._onPointerDown = this._onPointerDown.bind(this);
    this._onPointerMove = this._onPointerMove.bind(this);
    this._onPointerUp = this._onPointerUp.bind(this);
    this._onWheel = this._onWheel.bind(this);

    this._attach();
    this.apply();
  }

  markInteraction() {
    this._lastInteractionMs = nowMs();
  }

  _attach() {
    this.canvas.addEventListener('pointerdown', this._onPointerDown);
    window.addEventListener('pointermove', this._onPointerMove, { passive: false });
    window.addEventListener('pointerup', this._onPointerUp, { passive: true });
    this.canvas.addEventListener('wheel', this._onWheel, { passive: false });
  }

  detach() {
    this.canvas.removeEventListener('pointerdown', this._onPointerDown);
    window.removeEventListener('pointermove', this._onPointerMove);
    window.removeEventListener('pointerup', this._onPointerUp);
    this.canvas.removeEventListener('wheel', this._onWheel);
  }

  _onPointerDown(e) {
    this._dragging = true;
    this._lastX = e.clientX;
    this._lastY = e.clientY;
    this._lastMoveMs = nowMs();
    this._yawVel = 0;
    this._pitchVel = 0;
    this.canvas.setPointerCapture?.(e.pointerId);
    this.markInteraction();
  }

  _onPointerMove(e) {
    if (!this._dragging) return;
    e.preventDefault();
    const dx = e.clientX - this._lastX;
    const dy = e.clientY - this._lastY;
    this._lastX = e.clientX;
    this._lastY = e.clientY;

    // Sensitivity tuned for typical embed sizes.
    const deltaYaw = (this.invertDragX ? dx : -dx) * this.dragSensitivity;
    const deltaPitch = (this.invertDragY ? dy : -dy) * this.dragSensitivity;

    this.targetYaw += deltaYaw;
    this.targetPitch = clamp(this.targetPitch + deltaPitch, this.minPitch, this.maxPitch);

    const t = nowMs();
    const dt = Math.max(1, Math.min(50, t - (this._lastMoveMs ?? t)));
    this._lastMoveMs = t;
    this._yawVel = deltaYaw / dt;
    this._pitchVel = deltaPitch / dt;

    // Don't update the actual camera transform here; keep it lightweight.
    // The render loop (`tick`) applies smoothing every frame, which removes stutter/lag on some devices.
    this.markInteraction();
  }

  _onPointerUp() {
    this._dragging = false;
    // Stop "momentum" after the user releases drag (requested).
    this._yawVel = 0;
    this._pitchVel = 0;
    this._lastMoveMs = null;
    this.markInteraction();
  }

  _onWheel(e) {
    e.preventDefault();
    const delta = Math.sign(e.deltaY);
    const next = clamp(this.camera.fov + delta * 2.2, this.minFov, this.maxFov);
    this.setFov(next, { duration: 0.25 });
    this.markInteraction();
  }

  apply() {
    // For panorama viewing, camera stays at origin and we rotate it.
    this.camera.rotation.set(this.pitch, this.yaw, 0, 'YXZ');
  }

  tick(timeMs) {
    if (this._lastTickMs == null) this._lastTickMs = timeMs;
    const deltaMs = Math.max(0, Math.min(48, timeMs - this._lastTickMs));
    this._lastTickMs = timeMs;
    const idleFor = timeMs - this._lastInteractionMs;

    // Auto-rotate when enabled (immediate).
    if (this.autoRotateEnabled && !this._dragging) {
      this.targetYaw += this.autoRotateSpeed * deltaMs;
    }

    // Inertia glide after manual drag release (only while not "idle-autorotating").
    if (idleFor < this.idleDelayMs) {
      const friction = Math.pow(this.inertiaFriction, deltaMs / 16.67);
      this.targetYaw += this._yawVel * deltaMs;
      this.targetPitch = clamp(this.targetPitch + this._pitchVel * deltaMs, this.minPitch, this.maxPitch);
      this._yawVel *= friction;
      this._pitchVel *= friction;
    }

    // Damped smoothing towards target.
    // If the user is actively dragging, reduce smoothing to keep it feeling "direct"
    // while still running through the same codepath (prevents stutter).
    // Slightly increase damping while auto-rotating so motion is clearly visible.
    const baseDamping = this.autoRotateEnabled ? Math.max(this.damping, 0.03) : this.damping;
    const damping = this._dragging ? Math.max(baseDamping, 0.04) : baseDamping;
    const alpha = 1 - Math.exp(-damping * deltaMs);
    this.yaw += (this.targetYaw - this.yaw) * alpha;
    this.pitch += (this.targetPitch - this.pitch) * alpha;
    this.pitch = clamp(this.pitch, this.minPitch, this.maxPitch);
    this.apply();
  }

  setAutoRotateEnabled(enabled) {
    this.autoRotateEnabled = !!enabled;
    // Start immediately when enabled.
    if (this.autoRotateEnabled) {
      this._yawVel = 0;
      this._pitchVel = 0;
    }
    this.markInteraction();
  }

  /**
   * Smoothly rotate to a target yaw/pitch (in radians).
   */
  rotateTo({ yaw, pitch }, { duration = 0.8, ease = 'power2.out' } = {}) {
    this.markInteraction();
    const to = {
      yaw: typeof yaw === 'number' ? yaw : this.targetYaw,
      pitch: typeof pitch === 'number' ? clamp(pitch, this.minPitch, this.maxPitch) : this.targetPitch
    };
    gsap.to(this, {
      targetYaw: to.yaw,
      targetPitch: to.pitch,
      duration,
      ease,
      onStart: () => {
        this._yawVel = 0;
        this._pitchVel = 0;
      }
    });
  }

  setFov(fov, { duration = 0.6, ease = 'power2.out' } = {}) {
    const next = clamp(fov, this.minFov, this.maxFov);
    gsap.to(this.camera, {
      fov: next,
      duration,
      ease,
      onUpdate: () => this.camera.updateProjectionMatrix()
    });
  }
}


