/**
 * Viewer
 *
 * Main controller that wires together:
 * - Supabase loading (project/panoramas/hotspots/floorplans)
 * - Three.js scene render loop
 * - Panorama loading + transitions
 * - Hotspot navigation
 * - Floorplan overlay
 * - WebXR VR mode
 * - Analytics hooks
 */

import { gsap } from 'gsap';
import { SceneManager } from './SceneManager.js';
import { Panorama } from './Panorama.js';
import { Hotspot } from './Hotspot.js';
import { CameraController } from './CameraController.js';
import { Floorplan } from './Floorplan.js';
import { VRManager } from './VRManager.js';
import { Analytics } from './Analytics.js';
import { SupabaseService } from './SupabaseService.js';
import { resolveContainer, vector3ToLatLon } from './Utils.js';

export class Viewer {
  /**
   * @param {object} options
   * @param {HTMLElement|string} options.container
   * @param {string} options.projectId
   * @param {string} options.supabaseUrl
   * @param {string} options.supabaseAnonKey
   * @param {boolean} [options.debug] Enable console debug logs (also enabled by window.__P360_DEBUG = true)
   * @param {boolean} [options.enableVR]
   */
  constructor(options) {
    this.options = { enableVR: false, ...options };
    this.container = resolveContainer(this.options.container);
    this.container.classList.add('p360-root');

    this._destroyed = false;
    // Debug logging: off by default
    this._debug =
      !!this.options.debug ||
      (typeof window !== 'undefined' && !!window.__P360_DEBUG);
    this._project = null;
    this._panoramas = [];
    this._floorplans = [];
    this._hotspots = [];
    this._hotspotObjects = [];

    this._currentPanoramaId = null;
    this._currentFloorplanId = null;

    // View controls
    this._viewMode = '360'; // '360' | '3d' | '2d'
    // Zoom presets (FOV). "1x" is intentionally a bit zoomed-out for better perspective.
    this._zoomLevels = [1, 1.5, 2];
    this._zoomLevel = 1;
    this._zoomFovByLevel = {
      // Wider spread so zoom is clearly visible on all devices.
      // User request: slightly more zoomed-out across presets.
      1: 102,
      1.5: 78,
      2: 58
    };

    this.supabase = new SupabaseService({
      supabaseUrl: this.options.supabaseUrl,
      supabaseAnonKey: this.options.supabaseAnonKey
    });
    this.analytics = new Analytics({ supabase: this.supabase, projectId: this.options.projectId });

    this.sceneManager = new SceneManager({ container: this.container });
    this.cameraController = new CameraController({
      camera: this.sceneManager.camera,
      canvas: this.sceneManager.canvas
    });
    // Apply default zoom
    this._applyZoomLevel(this._zoomLevel, { immediate: true });

    this._hud = this._createHud();
    this.floorplan = new Floorplan({
      root: this.container,
      onNavigatePanorama: (id) => this._onFloorplanNavigate(id),
      onRoomClick: (room) => this._onFloorplanRoomClick(room),
      onRoomHover: (room) => this._onFloorplanRoomHover(room)
    });

    this.vr = new VRManager({
      renderer: this.sceneManager.renderer,
      scene: this.sceneManager.scene,
      camera: this.sceneManager.camera,
      onSelectIntersection: (hit) => this._onVrSelect(hit),
      onSessionStart: async () => {
        // Disable desktop pointer interactions while in XR.
        this.cameraController.markInteraction();
        await this.analytics.track('vr_entered', {});
      },
      onSessionEnd: async () => {
        await this.analytics.track('vr_exited', {});
      }
    });

    this._panorama = new Panorama({ radius: 500 });
    this._panoramaMesh = null;

    // 2D/3D overlay (TopView + MiddleCut carousel)
    this._overlayMode = 'none'; // 'none' | '2d' | '3d'
    this._overlayUrls = [];
    this._overlayIndex = 0;
    this._topViewUrl = null;
    this._middleCutUrls = [];
    this._overlay = this._createOverlay();
    // Cache for 3D overlay images (MiddleCut). Keeps navigation snappy and synced with counter.
    this._overlayImgCache = new Map(); // url -> { promise: Promise<void>, img: HTMLImageElement }
    this._overlayNavInFlight = false;

    // Editor mode state removed. Only view mode remains.
    this._tourData = null; // cached project tour_data object

    this._onCanvasClick = this._onCanvasClick.bind(this);
    this.sceneManager.canvas.addEventListener('click', this._onCanvasClick);

    // Best-effort session end on navigation/close. Cannot reliably await network here.
    this._onPageHide = () => {
      if (this._destroyed) return;
      this.analytics.track('session_end', { panoramaId: this._currentPanoramaId, reason: 'pagehide' });
    };
    window.addEventListener('pagehide', this._onPageHide);

    this.sceneManager.onBeforeRender((t) => {
      if (this._destroyed) return;
      if (!this.vr.isPresenting()) this.cameraController.tick(t);
    });
  }

  _dlog(...args) {
    if (!this._debug) return;
    // eslint-disable-next-line no-console
    console.debug('[Panorama360]', ...args);
  }

  _dwarn(...args) {
    if (!this._debug) return;
    // eslint-disable-next-line no-console
    console.warn('[Panorama360]', ...args);
  }

  async init() {
    await this.analytics.track('session_start', { userAgent: navigator.userAgent });
    await this._loadProjectData();

    const startId =
      this._project?.settings?.start_panorama_id ||
      this._panoramas?.[0]?.id ||
      null;
    if (!startId) throw new Error('Panorama360: project has no panoramas');

    if (this._project?.settings?.enable_vr === true || this.options.enableVR === true) {
      this.vr.enable({ domRoot: this._hud });
    }

    this.sceneManager.start();
    await this.loadPanorama(startId, { reason: 'initial' });
  }

  getCurrentPanoramaId() {
    return this._currentPanoramaId;
  }

  /**
   * Current view angles in degrees (matches tour_data yaw/pitch convention).
   * @returns {{yaw:number, pitch:number}}
   */
  getViewYawPitch() {
    const radToDeg = (r) => (r * 180) / Math.PI;
    // Normalize yaw to [-180, 180] to match existing app conventions.
    const normYaw = (deg) => {
      const v = ((deg + 180) % 360 + 360) % 360 - 180;
      return v;
    };
    const yawDeg = normYaw(radToDeg(this.cameraController?.yaw || 0));
    const pitchDeg = radToDeg(this.cameraController?.pitch || 0);
    return { yaw: yawDeg, pitch: pitchDeg };
  }

  async _loadProjectData() {
    const projectId = this.options.projectId;
    this._project = await this.supabase.getProject(projectId);
    this._panoramas = await this.supabase.getPanoramas(projectId);
    this._floorplans = await this.supabase.getFloorplans(projectId);
    this._tourData = this._project?.tour_data || this.supabase.getCachedTourData(projectId) || null;

    // Infer TopView + MiddleCut assets for 2D/3D modes.
    this._topViewUrl = this._inferTopViewUrl();
    this._middleCutUrls = await this._inferMiddleCutUrls();
    this._updateHudState?.();
  }

  _getRoomMetaMapFromProject() {
    const fp = this._project?.floorplan_data;
    if (!fp || typeof fp !== 'object') return {};
    const out = {};

    // Preferred: explicit rooms array from DB
    if (Array.isArray(fp.rooms)) {
      for (const r of fp.rooms) {
        const roomId = String(r?.roomId || r?.id || '').trim();
        if (!roomId) continue;
        out[roomId] = {
          name: r?.name ?? null,
          status: r?.status ?? null,
          panoramaId: r?.panoramaId ?? null
        };
      }
    }

    // Optional maps (merged)
    const roomStatus = fp.room_status && typeof fp.room_status === 'object' ? fp.room_status : null;
    const roomNames = fp.room_names && typeof fp.room_names === 'object' ? fp.room_names : null;
    const roomMap = fp.room_map && typeof fp.room_map === 'object' ? fp.room_map : null;

    if (roomStatus) {
      for (const [roomId, status] of Object.entries(roomStatus)) {
        out[roomId] = { ...(out[roomId] || {}), status: status ?? null };
      }
    }
    if (roomNames) {
      for (const [roomId, name] of Object.entries(roomNames)) {
        out[roomId] = { ...(out[roomId] || {}), name: name ?? null };
      }
    }
    if (roomMap) {
      for (const [roomId, panoramaId] of Object.entries(roomMap)) {
        out[roomId] = { ...(out[roomId] || {}), panoramaId: panoramaId ?? null };
      }
    }

    return out;
  }

  _getRoomIdForPanorama(pano) {
    if (!pano) return null;
    const map = this._project?.floorplan_data?.room_map || null;
    if (!map || typeof map !== 'object') return null;

    const panoId = pano?.id ? String(pano.id) : '';
    const panoName = pano?.name ? String(pano.name) : '';
    const panoUrl = pano?.image_url ? String(pano.image_url) : '';
    const panoUrlNoQuery = panoUrl.split('?')[0];
    const panoFile = panoUrl ? panoUrl.split('/').pop() : '';
    const panoFileNoQuery = panoFile.split('?')[0];

    // room_map values may be:
    // - panorama UUID (normalized schema)
    // - panorama "name"
    // - panorama image filename (compact schema, e.g. "Panorama_0_0_1_...webp")
    // - a full public URL (which must match by basename against signed URLs)
    for (const [roomId, ref] of Object.entries(map)) {
      if (!ref) continue;
      const v = String(ref);
      const vNoQuery = v.split('?')[0];
      const vFile = v.split('/').pop() || v;
      const vFileNoQuery = vFile.split('?')[0];
      if (
        v === panoId ||
        v === panoName ||
        v === panoFile ||
        v === panoFileNoQuery ||
        v === panoUrl ||
        vNoQuery === panoUrlNoQuery ||
        // Basename match: public URL in room_map vs signed URL in pano.image_url
        vFileNoQuery === panoFileNoQuery
      ) return roomId;
    }
    return null;
  }

  _inferTopViewUrl() {
    // Prefer projects.images["2d"] list (your new schema).
    const imgs2d = this._project?.images?.['2d'];
    if (Array.isArray(imgs2d)) {
      const top = imgs2d.find((x) => typeof x?.name === 'string' && x.name.startsWith('TopView_') && x.publicUrl) || null;
      if (top?.publicUrl) return top.publicUrl;
    }

    const fp = this._project?.floorplan_data || null;
    const direct =
      fp?.top_view_url ||
      fp?.topViewUrl ||
      fp?.top_view_image ||
      fp?.topViewImage ||
      fp?.top_view ||
      fp?.topView ||
      null;
    if (direct) return direct;

    // Heuristic: infer from first panorama image URL path (projects/{projectId}/TopView_0_0.webp)
    const base = this._inferProjectStorageBaseUrl();
    return base ? `${base}TopView_0_0.webp` : null;
  }

  async _inferMiddleCutUrls() {
    // Prefer projects.images["3d"] list (your new schema).
    const imgs3d = this._project?.images?.['3d'];
    if (Array.isArray(imgs3d)) {
      const urls = imgs3d
        .filter((x) => typeof x?.publicUrl === 'string' && x.publicUrl.trim())
        .slice()
        .sort((a, b) => String(a.name || '').localeCompare(String(b.name || '')))
        .map((x) => x.publicUrl);
      if (urls.length) return urls;
    }

    // Prefer explicit config in floorplan_data (optional).
    const fp = this._project?.floorplan_data || null;
    const direct =
      fp?.middle_cut_urls ||
      fp?.middleCutUrls ||
      fp?.middlecut_urls ||
      fp?.middleCut ||
      fp?.middle_cut ||
      null;
    if (Array.isArray(direct)) {
      return Array.from(new Set(direct.filter((u) => typeof u === 'string' && u.trim()))).sort((a, b) => a.localeCompare(b));
    }

    // Fallback 1: infer from panorama rows if they include image3d_url assets.
    const urls = [];
    for (const p of this._panoramas) {
      const u = p?.image3d_url;
      if (typeof u !== 'string') continue;
      if (!u.includes('MiddleCut_') || !u.toLowerCase().endsWith('.webp')) continue;
      urls.push(u);
    }
    const fromRows = Array.from(new Set(urls)).sort((a, b) => a.localeCompare(b));
    if (fromRows.length) return fromRows;

    // Fallback 2 (your requested behavior): probe common storage names under the project folder.
    // Example names: MiddleCut_0_0_0.webp, MiddleCut_0_0_6.webp
    const base = this._inferProjectStorageBaseUrl();
    if (!base) return [];
    return await this._probeMiddleCutUrls(base);
  }

  _inferProjectStorageBaseUrl() {
    // Try to infer the project storage folder base URL from either:
    // - any panorama image_url that contains "/projects/{projectId}/"
    // - or floorplan_data.image_url/svg_url
    const projectId = this.options.projectId;
    const marker = `/projects/${projectId}/`;

    const candidates = [
      this._panoramas.find((p) => typeof p.image_url === 'string' && p.image_url.includes(marker))?.image_url || null,
      this._project?.floorplan_data?.image_url || null,
      this._project?.floorplan_data?.svg_url || null
    ].filter(Boolean);

    for (const any of candidates) {
      if (typeof any !== 'string') continue;
      const idx = any.indexOf(marker);
      if (idx === -1) continue;
      return any.slice(0, idx + marker.length);
    }
    return null;
  }

  async _probeMiddleCutUrls(baseUrl) {
    // Best-effort HEAD probes (avoids needing Storage LIST permissions).
    const prefix = `${baseUrl}MiddleCut_0_0_`;
    const suffix = `.webp`;
    const indices = [];
    for (let i = 0; i <= 30; i++) indices.push(i);

    const exists = [];
    // Small concurrency to be polite.
    const concurrency = 6;
    let cursor = 0;
    const worker = async () => {
      while (cursor < indices.length) {
        const i = indices[cursor++];
        const url = `${prefix}${i}${suffix}`;
        try {
          const res = await fetch(url, { method: 'HEAD', mode: 'cors' });
          if (res.ok) exists.push(url);
        } catch {
          // ignore
        }
      }
    };
    await Promise.all(Array.from({ length: concurrency }, () => worker()));
    return exists.sort((a, b) => a.localeCompare(b));
  }

  _getPanoramaById(idOrRef) {
    if (!idOrRef) return null;
    const raw = String(idOrRef);
    const rawNoQuery = raw.split('?')[0];
    const ref = raw.toLowerCase();
    const refNoQuery = rawNoQuery.toLowerCase();
    const refFileNoQuery = (rawNoQuery.split('/').pop() || rawNoQuery).toLowerCase();
    return (
      this._panoramas.find((p) => String(p.id).toLowerCase() === ref) ||
      this._panoramas.find((p) => p.name && String(p.name).toLowerCase() === ref) ||
      // Full URL match (with/without query)
      this._panoramas.find((p) => {
        const u = (p.image_url || '').toString();
        const uNoQuery = u.split('?')[0];
        return u.toLowerCase() === ref || uNoQuery.toLowerCase() === refNoQuery;
      }) ||
      this._panoramas.find((p) => {
        const url = p.image_url || '';
        const filename = (url.split('/').pop() || '').toLowerCase();
        const filenameNoQuery = filename.split('?')[0];
        // Support:
        // - idOrRef is a filename ("Panorama_...webp")
        // - idOrRef is a full URL (public/signed), match by basename
        return (
          filename === ref ||
          filenameNoQuery === refNoQuery ||
          filenameNoQuery === refFileNoQuery
        );
      }) ||
      null
    );
  }

  _getFloorplanById(id) {
    return this._floorplans.find((f) => f.id === id) || null;
  }

  async loadPanorama(panoramaId, { reason = 'api' } = {}) {
    if (this._destroyed) return;
    const pano = this._getPanoramaById(panoramaId);
    if (!pano) throw new Error(`Panorama360: panorama not found: ${panoramaId}`);

    // Fade + blur transition (better UX).
    const canvas = this.sceneManager.canvas;
    this.container.classList.add('is-transitioning');
    await this._tween(canvas, { opacity: 0.0, duration: 0.25, ease: 'power1.out' });

    // Replace panorama sphere (always the 360 panorama; 2D/3D are overlay images only).
    const mesh = await this._panorama.load(pano.image_url);
    if (this._panoramaMesh) this.sceneManager.scene.remove(this._panoramaMesh);
    this._panoramaMesh = mesh;
    this.sceneManager.scene.add(mesh);

    // Derive a theme color from the panorama image so hotspot icons can be outlined
    // with the pano's background color (more cohesive + readable).
    const panoThemeOutline = this._tryComputeAverageColorHex(mesh?.material?.map) || 0x4f8cff;

    // Load hotspots for this panorama.
    const hotspotRows = await this.supabase.getHotspotsByPanorama(pano.id);
    this._setHotspots(hotspotRows, { outline: panoThemeOutline });

    // Update floorplan overlay.
    this._currentPanoramaId = pano.id;
    this._currentFloorplanId = pano.floorplan_id || null;
    // In compact-schema mode, panoramas may not have floorplan_id at all.
    // If so, fall back to the first available floorplan from `projects.floorplan_data`.
    const fp =
      pano.floorplan_id
        ? this._getFloorplanById(pano.floorplan_id)
        : (this._floorplans[0] || null);
    await this.floorplan.setData(fp, this._panoramas);
    this.floorplan.setRoomMeta(this._getRoomMetaMapFromProject());
    // Highlight current room:
    // - prefer panorama.room_id
    // - otherwise inverse-lookup from projects.floorplan_data.room_map (room -> panoramaId)
    this.floorplan.setActiveRoom((pano.room_id || this._getRoomIdForPanorama(pano)) || null);

    await this.analytics.track('panorama_loaded', { panoramaId: pano.id, reason, viewMode: this._viewMode });
    await this._tween(canvas, { opacity: 1.0, duration: 0.35, ease: 'power1.out' });
    this.container.classList.remove('is-transitioning');

    // Background preload for linked panoramas (best-effort).
    for (const row of hotspotRows || []) {
      if ((row?.type === 'navigate' || row?.type === 'door') && row?.target_panorama_id) {
        const target = this._getPanoramaById(row.target_panorama_id);
        if (target?.image_url) {
          // Trigger TextureLoader + THREE.Cache storage.
          this._panorama._loadTexture(target.image_url).catch(() => {});
        }
        if (target?.image3d_url) {
          this._panorama._loadTexture(target.image3d_url).catch(() => {});
        }
      }
    }
  }

  _setHotspots(rows, theme = null) {
    for (const h of this._hotspots) {
      this.sceneManager.scene.remove(h.object3d);
      h.dispose();
    }
    this._hotspots = [];
    this._hotspotObjects = [];

    for (const row of rows || []) {
      const hotspot = new Hotspot(row, { radius: 495 });
      if (theme && typeof hotspot.setTheme === 'function') {
        hotspot.setTheme({ outline: theme.outline, accent: 0x4f8cff, glyph: 0x0b0f19 });
      }
      this._hotspots.push(hotspot);
      this._hotspotObjects.push(hotspot.object3d);
      this.sceneManager.scene.add(hotspot.object3d);
    }

    this.vr.setHotspotObjects(this._hotspotObjects);
  }

  _tryComputeAverageColorHex(texture) {
    try {
      const img = texture?.image;
      if (!img) return null;
      // Support HTMLImageElement (common) and ImageBitmap.
      const w = img.width || img.naturalWidth;
      const h = img.height || img.naturalHeight;
      if (!(w > 0 && h > 0)) return null;

      const canvas = document.createElement('canvas');
      const tw = 32;
      const th = 16;
      canvas.width = tw;
      canvas.height = th;
      const ctx = canvas.getContext('2d', { willReadFrequently: true });
      // Sample around the horizon band (middle of the equirectangular),
      // which tends to represent the pano "background" color better than ceiling/floor.
      const sy = Math.floor(h * 0.35);
      const sh = Math.max(1, Math.floor(h * 0.30));
      ctx.drawImage(img, 0, sy, w, sh, 0, 0, tw, th);
      const data = ctx.getImageData(0, 0, tw, th).data;
      let r = 0, g = 0, b = 0, n = 0;
      for (let i = 0; i < data.length; i += 4) {
        const a = data[i + 3];
        if (a < 8) continue;
        r += data[i];
        g += data[i + 1];
        b += data[i + 2];
        n++;
      }
      if (!n) return null;
      r = Math.round(r / n);
      g = Math.round(g / n);
      b = Math.round(b / n);
      return (r << 16) | (g << 8) | b;
    } catch {
      return null;
    }
  }

  _pickHotspotFromClick(evt) {
    this.sceneManager.setPointerFromClient(evt.clientX, evt.clientY);
    const hits = this.sceneManager.intersectObjects(this._hotspotObjects, true);
    return hits[0] || null;
  }

  async _onCanvasClick(evt) {
    if (this._destroyed) return;
    if (this.vr.isPresenting()) return;

    const hit = this._pickHotspotFromClick(evt);
    if (!hit) return;

    const hotspot = this._findHotspotFromObject(hit.object);
    if (!hotspot) return;

    await this._handleHotspotActivation(hotspot, { source: 'click' });
  }

  async _onVrSelect(hit) {
    if (this._destroyed) return;
    if (!hit) return;
    const hotspot = this._findHotspotFromObject(hit.object);
    if (!hotspot) return;
    await this._handleHotspotActivation(hotspot, { source: 'vr_select' });
  }

  _findHotspotFromObject(obj) {
    let cur = obj;
    for (let i = 0; i < 6 && cur; i++) {
      if (cur.userData?.hotspot) return cur.userData.hotspot;
      cur = cur.parent;
    }
    return null;
  }

  async _handleHotspotActivation(hotspot, { source }) {
    const row = hotspot.data;
    await this.analytics.track('hotspot_clicked', {
      source,
      hotspotId: row.id,
      panoramaId: row.panorama_id,
      targetPanoramaId: row.target_panorama_id || null
    });

    if ((row.type === 'navigate' || row.type === 'door') && row.target_panorama_id) {
      await this.loadPanorama(row.target_panorama_id, { reason: 'hotspot' });
      return;
    }

    // Optional camera animation payload support (jsonb camera).
    if (row.camera && typeof row.camera === 'object') {
      const { yaw, pitch, fov } = row.camera;
      if (typeof yaw === 'number' || typeof pitch === 'number') this.cameraController.rotateTo({ yaw, pitch });
      if (typeof fov === 'number') this.cameraController.setFov(fov);
    }
  }

  async _onFloorplanNavigate(panoramaId) {
    await this.analytics.track('floorplan_click', { panoramaId });
    await this.loadPanorama(panoramaId, { reason: 'floorplan' });
  }

  async _onFloorplanRoomClick(roomId) {
    const info =
      typeof roomId === 'string'
        ? { roomId, roomName: null, panoramaId: null }
        : (roomId || { roomId: null, roomName: null, panoramaId: null });
    const rid = info?.roomId || null;
    if (!rid) return;
    this._dlog('floorplan room click', { roomId: rid, panoramaId: info?.panoramaId || null, status: info?.status || null });

    // Priority:
    // 1) projects.floorplan_data.room_map[roomId]
    // 2) Explicit mapping from SVG: data-panorama-id
    // 3) roomId -> panoramas[].room_id mapping
    const map = this._project?.floorplan_data?.room_map || null;
    const mappedId = map && typeof map === 'object' ? map[rid] : null;
    let mapped = mappedId ? this._getPanoramaById(mappedId) : null;
    const direct = info?.panoramaId ? this._getPanoramaById(info.panoramaId) : null;
    const byRoom = this._panoramas.find((p) => p.room_id === rid) || null;

    // If room_map points to a full public URL that is not in the project's panorama list,
    // still allow navigation by treating it as an in-memory panorama.
    //
    // This supports scenarios where:
    // - floorplan_data belongs to project A
    // - room_map references a panorama image URL stored under project B folder (or any external URL)
    // - the panoramas table / tour_data for project A doesn't include that exact URL
    if (!mapped && typeof mappedId === 'string') {
      const url = mappedId.trim();
      const looksLikeUrl = /^https?:\/\//i.test(url);
      const looksLikeImage =
        /\.(webp|jpe?g|png)$/i.test(url.split('?')[0] || '') ||
        /\/storage\/v1\/object\/public\//i.test(url);
      if (looksLikeUrl && looksLikeImage) {
        const synthetic = {
          id: url,
          project_id: this.options.projectId,
          name: url.split('/').pop() || null,
          image_url: url,
          image3d_url: null,
          room_id: rid,
          floorplan_id: null,
          floorplan_x: null,
          floorplan_y: null
        };
        // Add to the in-memory list so future lookups (and mode toggles) keep working.
        const exists = this._getPanoramaById(synthetic.id);
        if (!exists) this._panoramas.push(synthetic);
        mapped = synthetic;
        this._dlog('floorplan room_map URL fallback: created synthetic panorama', { roomId: rid, url });
      }
    }

    const pano = mapped || direct || byRoom || null;
    this._dlog('floorplan resolution', {
      roomId: rid,
      mappedId: mappedId || null,
      resolved: pano ? { id: pano.id, image_url: pano.image_url } : null,
      panoramasLoaded: Array.isArray(this._panoramas) ? this._panoramas.length : 0
    });

    // Status-aware behavior (DB-driven): sold rooms are not navigable by default.
    const status = (info?.status || null);
    if (String(status || '').toLowerCase() === 'sold') {
      await this.analytics.track('floorplan_click', { roomId: rid, panoramaId: pano?.id || null, status: 'sold', blocked: true });
      return;
    }

    await this.analytics.track('floorplan_click', { roomId: rid, panoramaId: pano?.id || null });
    if (!pano?.id) {
      this._dwarn('floorplan navigation failed: no panorama resolved', { roomId: rid, mappedId: mappedId || null, svgPanoramaId: info?.panoramaId || null });
      this.container.dispatchEvent(new CustomEvent('p360:floorplanNavigateFailed', {
        detail: {
          roomId: rid,
          mappedId: mappedId || null,
          svgPanoramaId: info?.panoramaId || null,
          reason: 'no_panorama_resolved'
        },
        bubbles: true
      }));
      return;
    }

    try {
      await this.loadPanorama(pano.id, { reason: 'floorplan_room' });
    } catch (err) {
      this._dwarn('floorplan navigation failed: loadPanorama threw', { roomId: rid, panoramaId: pano.id, error: String(err?.message || err) });
      this.container.dispatchEvent(new CustomEvent('p360:floorplanNavigateFailed', {
        detail: {
          roomId: rid,
          panoramaId: pano.id,
          mappedId: mappedId || null,
          svgPanoramaId: info?.panoramaId || null,
          reason: 'loadPanorama_error',
          error: String(err?.message || err)
        },
        bubbles: true
      }));
    }
  }

  _onFloorplanRoomHover(room) {
    if (!room?.roomId) return;

    // Viewer-only widget: hover just highlights the room via Floorplan CSS.
  }

  _pickHotspotFromClick(evt) {
    this.sceneManager.setPointerFromClient(evt.clientX, evt.clientY);
    const hits = this.sceneManager.intersectObjects(this._hotspotObjects, true);
    return hits[0] || null;
  }

  async _onCanvasClick(evt) {
    if (this._destroyed) return;
    if (this.vr.isPresenting()) return;

    const hit = this._pickHotspotFromClick(evt);
    if (!hit) return;

    const hotspot = this._findHotspotFromObject(hit.object);
    if (!hotspot) return;

    await this._handleHotspotActivation(hotspot, { source: 'click' });
  }

  _toggleFloorplan(open) {
    this.floorplan.toggle();
    this._updateHudState?.();
  }

  _applyZoomLevel(level, { immediate = false } = {}) {
    const fov = this._zoomFovByLevel[level] ?? this.sceneManager.camera.fov;
    if (immediate) {
      this.sceneManager.camera.fov = fov;
      this.sceneManager.camera.updateProjectionMatrix();
      return;
    }
    this.cameraController.setFov(fov, { duration: 0.35 });
  }

  _cycleZoom() {
    const idx = this._zoomLevels.indexOf(this._zoomLevel);
    const next = this._zoomLevels[(idx + 1) % this._zoomLevels.length];
    this._zoomLevel = next;
    this._applyZoomLevel(next);
    this._updateHudState?.();
  }

  _setViewMode(mode) {
    this._viewMode = mode;
    this._updateHudState?.();
    this.container.classList.toggle('p360-mode-2d', mode === '2d');
    this.container.classList.toggle('p360-mode-3d', mode === '3d');
    // Show/hide overlays depending on mode.
    if (mode === '360') {
      this._setOverlay({ mode: 'none' });
      this.sceneManager.canvas.style.pointerEvents = 'auto';
      // show 3D hotspots
      for (const h of this._hotspots) h.object3d.visible = true;
    } else if (mode === '2d') {
      // 2D mode is the optional TopView overlay (if available).
      this._setOverlay({ mode: '2d', urls: this._topViewUrl ? [this._topViewUrl] : [] });
      this.sceneManager.canvas.style.pointerEvents = 'none';
      for (const h of this._hotspots) h.object3d.visible = false;
    } else if (mode === '3d') {
      this._setOverlay({ mode: '3d', urls: this._middleCutUrls });
      this.sceneManager.canvas.style.pointerEvents = 'none';
      for (const h of this._hotspots) h.object3d.visible = false;
    }

    if (mode === '360' && this._currentPanoramaId) {
      this.loadPanorama(this._currentPanoramaId, { reason: 'mode' }).catch(() => {});
    }
  }

  _createOverlay() {
    const wrap = document.createElement('div');
    wrap.className = 'p360-overlay';
    wrap.style.display = 'none';

    const img = document.createElement('img');
    img.className = 'p360-overlay-img';
    img.alt = 'Overlay view';
    img.decoding = 'async';
    img.loading = 'eager';

    // Bottom pager UI (arrows + 1/N counter), matching design mock.
    const pager = document.createElement('div');
    pager.className = 'p360-overlay-pager';
    pager.style.display = 'none';

    const left = document.createElement('button');
    left.type = 'button';
    left.className = 'p360-overlay-pager-btn p360-overlay-pager-btn-left';
    left.setAttribute('aria-label', 'Previous');
    left.textContent = '←';
    left.addEventListener('click', () => this._overlayStep(-1));

    const count = document.createElement('span');
    count.className = 'p360-overlay-pager-count';
    count.setAttribute('aria-live', 'polite');
    count.textContent = '1/1';

    const right = document.createElement('button');
    right.type = 'button';
    right.className = 'p360-overlay-pager-btn p360-overlay-pager-btn-right';
    right.setAttribute('aria-label', 'Next');
    right.textContent = '→';
    right.addEventListener('click', () => this._overlayStep(1));

    pager.append(left, count, right);

    wrap.append(img, pager);
    this.container.appendChild(wrap);

    return { wrap, img, pager, count, left, right };
  }

  _preloadOverlayUrl(url) {
    if (!url) return Promise.resolve();
    const existing = this._overlayImgCache.get(url);
    if (existing?.promise) return existing.promise;

    const img = new Image();
    img.decoding = 'async';

    const promise = new Promise((resolve) => {
      const done = () => resolve();
      img.onload = async () => {
        try {
          if (img.decode) await img.decode();
        } catch {}
        done();
      };
      img.onerror = done;
      img.src = url;
      if (img.complete && img.naturalWidth > 0) {
        Promise.resolve()
          .then(async () => {
            try {
              if (img.decode) await img.decode();
            } catch {}
          })
          .finally(done);
      }
    });

    this._overlayImgCache.set(url, { promise, img });
    return promise;
  }

  _preloadOverlayNeighbors() {
    if (this._overlayMode !== '3d') return;
    const urls = this._overlayUrls || [];
    const n = urls.length;
    if (n <= 0) return;
    const idx = this._overlayIndex || 0;
    const cur = urls[idx];
    const next = urls[(idx + 1) % n];
    const prev = urls[(idx - 1 + n) % n];
    this._preloadOverlayUrl(cur);
    this._preloadOverlayUrl(next);
    this._preloadOverlayUrl(prev);
  }

  async _setOverlayIndex(nextIndex, { animate = true } = {}) {
    const urls = this._overlayUrls || [];
    const n = urls.length;
    if (n <= 0) return;
    const idx = ((nextIndex % n) + n) % n;
    const url = urls[idx];
    if (!url) return;

    if (this._overlayNavInFlight) return;
    this._overlayNavInFlight = true;
    this._overlay.left.disabled = true;
    this._overlay.right.disabled = true;
    this._overlay.wrap.classList.add('is-loading');

    await this._preloadOverlayUrl(url);

    if (animate) {
      this._overlay.img.style.opacity = '0';
      await new Promise((r) => requestAnimationFrame(() => r()));
    }

    this._overlay.img.src = url;
    this._overlayIndex = idx;
    this._updateOverlayPager?.();
    this._preloadOverlayNeighbors();

    if (animate) {
      await new Promise((r) => requestAnimationFrame(() => r()));
      this._overlay.img.style.opacity = '1';
    }

    const showNav = this._overlayMode === '3d' && urls.length > 1;
    this._overlay.left.disabled = !showNav;
    this._overlay.right.disabled = !showNav;
    this._overlay.wrap.classList.remove('is-loading');
    this._overlayNavInFlight = false;
  }

  _setOverlay({ mode, urls = [] }) {
    this._overlayMode = mode;
    this._overlayUrls = Array.isArray(urls) ? urls.filter(Boolean) : [];
    this._overlayIndex = 0;

    const has = this._overlayUrls.length > 0;
    this._overlay.wrap.style.display = (mode !== 'none' && has) ? 'block' : 'none';
    if (has) this._setOverlayIndex(0, { animate: false }).catch(() => {});

    const showNav = mode === '3d' && this._overlayUrls.length > 1;
    this._overlay.pager.style.display = showNav ? 'flex' : 'none';
    this._overlay.left.disabled = !showNav;
    this._overlay.right.disabled = !showNav;

    this._updateOverlayPager?.();
  }

  _overlayStep(dir) {
    if (this._overlayMode !== '3d') return;
    const n = this._overlayUrls.length;
    if (n <= 1) return;
    const next = (this._overlayIndex + dir + n) % n;
    this._setOverlayIndex(next, { animate: true }).catch(() => {});
  }

  _updateOverlayPager() {
    const n = this._overlayUrls.length || 0;
    if (!this._overlay?.count) return;
    if (n <= 0) {
      this._overlay.count.textContent = '0/0';
      return;
    }
    this._overlay.count.textContent = `${this._overlayIndex + 1}/${n}`;
  }

  async enterVR() {
    await this.vr.requestEnter();
  }

  async exitVR() {
    await this.vr.exit();
  }

  _tween(target, vars) {
    return new Promise((resolve) => {
      gsap.to(target, { ...vars, onComplete: resolve });
    });
  }

  _createHud() {
    const hud = document.createElement('div');
    hud.className = 'p360-hud';

    // Top-right fullscreen toggle
    const topRight = document.createElement('div');
    topRight.className = 'p360-hud-topright';

    const fsBtn = document.createElement('button');
    fsBtn.type = 'button';
    fsBtn.className = 'p360-btn p360-btn-icon p360-btn-fullscreen';
    fsBtn.title = 'Fullscreen';
    fsBtn.setAttribute('aria-label', 'Toggle fullscreen');

    const isFs = () => {
      const el = document.fullscreenElement;
      return !!el && (el === this.container || this.container.contains(el));
    };

    const updateFs = () => {
      const active = isFs();
      fsBtn.classList.toggle('is-active', active);
      fsBtn.title = active ? 'Exit fullscreen' : 'Fullscreen';
      fsBtn.setAttribute('aria-label', active ? 'Exit fullscreen' : 'Enter fullscreen');
    };

    const toggleFs = async () => {
      try {
        if (isFs()) await document.exitFullscreen();
        else await this.container.requestFullscreen({ navigationUI: 'hide' });
      } catch {
        // Ignore fullscreen errors (e.g. not allowed without user gesture)
      } finally {
        updateFs();
      }
    };

    fsBtn.addEventListener('click', () => { void toggleFs(); });
    this._onFullscreenChange = () => updateFs();
    document.addEventListener('fullscreenchange', this._onFullscreenChange);
    updateFs();

    topRight.appendChild(fsBtn);

    // Right-side mode switch (2D / 3D / 360)
    const right = document.createElement('div');
    right.className = 'p360-hud-right';

    const btn2d = document.createElement('button');
    btn2d.type = 'button';
    btn2d.className = 'p360-btn p360-btn-mode p360-btn-mode-2d';
    btn2d.textContent = '2D';
    btn2d.title = 'Top view';
    btn2d.addEventListener('click', () => this._setViewMode('2d'));

    const btn360 = document.createElement('button');
    btn360.type = 'button';
    btn360.className = 'p360-btn p360-btn-mode p360-btn-mode-360';
    btn360.textContent = '360°';
    btn360.title = '360 panorama viewer';
    btn360.addEventListener('click', () => this._setViewMode('360'));

    const btn3d = document.createElement('button');
    btn3d.type = 'button';
    btn3d.className = 'p360-btn p360-btn-mode p360-btn-mode-3d';
    btn3d.textContent = '3D';
    btn3d.title = '3D images (MiddleCut)';
    btn3d.addEventListener('click', () => this._setViewMode('3d'));

    right.append(btn2d, btn3d, btn360);

    // Bottom controls: zoom cycle + auto-rotate toggle
    const bottom = document.createElement('div');
    bottom.className = 'p360-hud-bottom p360-hud-bottom-pill';

    const zoomBtn = document.createElement('button');
    zoomBtn.type = 'button';
    zoomBtn.className = 'p360-btn p360-btn-pill';
    zoomBtn.title = 'Cycle zoom';
    zoomBtn.addEventListener('click', () => this._cycleZoom());

    const autoBtn = document.createElement('button');
    autoBtn.type = 'button';
    autoBtn.className = 'p360-btn p360-btn-pill p360-btn-autorotate';
    autoBtn.textContent = '';
    autoBtn.setAttribute('aria-label', 'Toggle auto-rotate');
    autoBtn.title = 'Toggle auto-rotate';
    autoBtn.addEventListener('click', () => {
      const next = !this.cameraController.autoRotateEnabled;
      this.cameraController.setAutoRotateEnabled(next);
      // UX: when enabling auto-rotate, gently recenter vertical view so rotation feels "level/centered".
      if (next) {
        this.cameraController.rotateTo(
          { pitch: 0 },
          { duration: 0.9, ease: 'power2.out' }
        );
      }
      this._updateHudState?.();
    });

    bottom.append(zoomBtn, autoBtn);

    // Keep references for state updates.
    this._updateHudState = () => {
      zoomBtn.textContent = `${this._zoomLevel}x`;
      autoBtn.classList.toggle('is-active', this.cameraController.autoRotateEnabled);
      btn2d.classList.toggle('is-active', this._viewMode === '2d');
      btn360.classList.toggle('is-active', this._viewMode === '360');
      btn3d.classList.toggle('is-active', this._viewMode === '3d');
      // Disable 2D if no TopView image inferred
      const has2d = !!this._topViewUrl;
      btn2d.disabled = !has2d;
      btn2d.style.opacity = has2d ? '1' : '0.45';
      // Disable 3D if no MiddleCut images inferred
      const has3d = Array.isArray(this._middleCutUrls) && this._middleCutUrls.length > 0;
      btn3d.disabled = !has3d;
      btn3d.style.opacity = has3d ? '1' : '0.45';
      zoomBtn.classList.toggle('is-active', this._zoomLevel !== 1);
    };
    this._updateHudState();

    hud.append(topRight, right, bottom);
    this.container.appendChild(hud);
    return hud;
  }

  async destroy() {
    if (this._destroyed) return;
    this._destroyed = true;

    await this.analytics.track('session_end', { panoramaId: this._currentPanoramaId });

    window.removeEventListener('pagehide', this._onPageHide);
    this.sceneManager.canvas.removeEventListener('click', this._onCanvasClick);
    this.cameraController.detach();
    if (this._onFullscreenChange) document.removeEventListener('fullscreenchange', this._onFullscreenChange);
    this.floorplan.destroy();
    this.vr.destroy();
    this._panorama?.dispose();

    for (const h of this._hotspots) h.dispose();
    this._hotspots = [];
    this._hotspotObjects = [];

    this.sceneManager.destroy();
    if (this._hud?.parentNode) this._hud.parentNode.removeChild(this._hud);
  }
}


