/**
 * Analytics
 *
 * NO-OP analytics implementation.
 *
 * This project intentionally does not write any analytics events to Supabase.
 * We keep this class so existing viewer code can call `analytics.track(...)`
 * without needing to change all call sites.
 */

export class Analytics {
  /**
   * @param {object} opts
   * @param {import('./SupabaseService.js').SupabaseService} [opts.supabase]
   * @param {string} [opts.projectId] Panorama360 project UUID (from your `projects` table)
   * @param {string} [opts.supabaseUrl] optional override (otherwise uses Vite env)
   * @param {string} [opts.supabaseAnonKey] optional override (otherwise uses Vite env)
   */
  constructor({ supabase, projectId, supabaseUrl, supabaseAnonKey } = {}) {
    void supabase;
    void projectId;
    void supabaseUrl;
    void supabaseAnonKey;
  }

  async track(event, payload = {}) {
    void event;
    void payload;
    return;
  }
}


